import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    connection = psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )
    
    cursor = connection.cursor()
    
    query = """SELECT * FROM users"""
    if username:
        query += f" WHERE username = %s"
    if email:
        query += f" AND email = %s"
    if role:
        query += f" AND role = %s"
    if status:
        query += f" AND status = %s"
    
    cursor.execute(query, (username, email, role, status))
    
    results = cursor.fetchall()
    
    return results